--
-- Table structure for table `caipiao_recharge`
--

DROP TABLE IF EXISTS `caipiao_recharge`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_recharge` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `uid` int(11) NOT NULL COMMENT 'ID người dùng',
  `username` char(30) NOT NULL COMMENT 'Tên đăng nhập',
  `paytype` char(20) NOT NULL COMMENT 'Mã phương thức nạp',
  `paytypetitle` varchar(60) NOT NULL COMMENT 'Tiêu đề phương thức nạp',
  `paytypename` varchar(50) DEFAULT '' COMMENT 'Tên phương thức nạp',
  `trano` char(60) NOT NULL COMMENT 'Mã giao dịch',
  `threetrano` char(255) NOT NULL COMMENT 'Mã đơn bên thứ 3',
  `amount` decimal(12,0) NOT NULL COMMENT 'Số tiền nạp',
  `fee` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT 'Phí giao dịch',
  `actualamount` decimal(12,2) NOT NULL COMMENT 'Số tiền thực nhận',
  `actualfee` decimal(12,2) NOT NULL COMMENT 'Phí thực tế',
  `oldaccountmoney` decimal(12,2) NOT NULL COMMENT 'Số dư cũ',
  `newaccountmoney` decimal(12,2) NOT NULL COMMENT 'Số dư mới',
  `remark` varchar(155) NOT NULL COMMENT 'Ghi chú',
  `payname` varchar(255) NOT NULL COMMENT 'Tên tài khoản ngân hàng nạp',
  `fuyanma` int(11) NOT NULL COMMENT 'Mã xác minh',
  `isauto` tinyint(4) NOT NULL DEFAULT '1' COMMENT 'Loại: 1-tự động, 2-thủ công',
  `sdtype` tinyint(4) NOT NULL DEFAULT '0' COMMENT 'Loại nạp thủ công: 1-nạp, -1-rút',
  `state` tinyint(4) NOT NULL COMMENT 'Trạng thái: 0-chờ duyệt, 1-đã duyệt, -1-đã hủy',
  `oddtime` int(11) NOT NULL COMMENT 'Thời gian tạo',
  `stateadmin` char(30) NOT NULL COMMENT 'Quản trị viên duyệt',
  PRIMARY KEY (`id`),
  KEY `trano` (`trano`),
  KEY `username` (`username`),
  KEY `uid` (`uid`),
  KEY `isauto` (`isauto`),
  KEY `oddtime` (`oddtime`),
  KEY `paytype` (`paytype`),
  KEY `sdtype` (`sdtype`)
) ENGINE=InnoDB AUTO_INCREMENT=383 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='Lịch sử nạp tiền';
/*!40101 SET character_set_client = @saved_cs_client */;

